import React, { useState, useEffect } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { AdminService } from '../../../services/api';
import { ArrowLeft, Save, Upload, Layers } from 'lucide-react';
import toast from 'react-hot-toast';

export const AdminSeriesForm = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const [loading, setLoading] = useState(false);
  const [formData, setFormData] = useState({
    Title_En: '',
    Title_Ar: '',
    Artist_ID: '',
    Description: ''
  });

  useEffect(() => {
    if (id) {
      AdminService.getSeriesById(id).then((res: any) => {
        setFormData(res.data);
      });
    }
  }, [id]);

  const handleManualSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    try {
      await AdminService.upsertSeries(formData);
      toast.success("Series Updated");
      navigate('/admin/series');
    } catch (err) { toast.error("Sync Failed"); }
    finally { setLoading(false); }
  };

  return (
    <div className="max-w-4xl mx-auto p-8 space-y-10">
      <button onClick={() => navigate(-1)} className="flex items-center gap-2 text-gray-400 font-bold text-[10px] uppercase tracking-widest hover:text-primary transition-colors">
        <ArrowLeft size={14} /> Back
      </button>

      <div className="bg-white dark:bg-[#0f0f0f] p-10 rounded-[3rem] border border-gray-100 dark:border-white/5 shadow-xl">
        <h2 className="text-3xl font-black italic uppercase mb-8">{id ? 'Edit' : 'New'} <span className="text-primary">Series</span></h2>
        <form onSubmit={handleManualSubmit} className="space-y-6">
          <div className="space-y-2">
            <label className="text-[10px] font-black uppercase text-gray-400 ml-2">Series Title (EN)</label>
            <input value={formData.Title_En} onChange={e => setFormData({...formData, Title_En: e.target.value})} className="w-full bg-gray-50 dark:bg-white/5 p-4 rounded-2xl dark:text-white" required />
          </div>
          <div className="space-y-2">
            <label className="text-[10px] font-black uppercase text-gray-400 ml-2">Artist ID</label>
            <input value={formData.Artist_ID} onChange={e => setFormData({...formData, Artist_ID: e.target.value})} className="w-full bg-gray-50 dark:bg-white/5 p-4 rounded-2xl dark:text-white" required />
          </div>
          <button type="submit" className="w-full bg-black text-white py-5 rounded-2xl font-black uppercase tracking-widest hover:bg-primary transition-all">Save Series</button>
        </form>
      </div>
    </div>
  );
};
